"use client";

import { useState, useEffect, useCallback } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { KeyValuePair, AnswerMode } from "@/app/page";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Check, X, Sparkles } from "lucide-react";

interface QuizModeProps {
  pairs: KeyValuePair[];
  answerMode: AnswerMode;
  setAnswerMode: React.Dispatch<React.SetStateAction<AnswerMode>>;
}

export function QuizMode({ pairs, answerMode, setAnswerMode }: QuizModeProps) {
  const [currentPair, setCurrentPair] = useState<KeyValuePair | null>(null);
  const [winStreak, setWinStreak] = useState(0);
  const [feedback, setFeedback] = useState<"success" | "error" | null>(null);
  const [selectedAnswer, setSelectedAnswer] = useState("");
  const [manualInput, setManualInput] = useState("");
  const [options, setOptions] = useState<string[]>([]);

  const validPairs = pairs.filter((p) => p.key.trim() && p.value.trim());

  const getRandomPair = useCallback(() => {
    if (validPairs.length === 0) return null;
    const randomIndex = Math.floor(Math.random() * validPairs.length);
    return validPairs[randomIndex];
  }, [validPairs]);

  const generateOptions = useCallback(
    (correctValue: string) => {
      if (answerMode === "all-values") {
        const allValues = validPairs.map((p) => p.value);
        return [...new Set(allValues)];
      } else {
        const otherValues = validPairs
          .filter((p) => p.value !== correctValue)
          .map((p) => p.value);
        const shuffledOthers = [...new Set(otherValues)].sort(
          () => Math.random() - 0.5
        );
        const wrongOptions = shuffledOthers.slice(0, 2);
        const allOptions = [correctValue, ...wrongOptions];
        return allOptions.sort(() => Math.random() - 0.5);
      }
    },
    [validPairs, answerMode]
  );

  const nextQuestion = useCallback(() => {
    const newPair = getRandomPair();
    if (newPair) {
      setCurrentPair(newPair);
      if (answerMode !== "manual") {
        setOptions(generateOptions(newPair.value));
      }
      setSelectedAnswer("");
      setManualInput("");
      setFeedback(null);
    }
  }, [getRandomPair, answerMode, generateOptions]);

  const handleAnswer = (answer: string) => {
    if (!currentPair || feedback) return;

    const isCorrect = answer === currentPair.value;

    if (isCorrect) {
      setFeedback("success");
      setWinStreak((prev) => prev + 1);
      setTimeout(() => {
        nextQuestion();
      }, 800);
    } else {
      setFeedback("error");
      setWinStreak(0);
      setTimeout(() => {
        nextQuestion();
      }, 1500);
    }
  };

  const handleManualSubmit = () => {
    if (manualInput.trim()) {
      handleAnswer(manualInput.trim());
    }
  };

  useEffect(() => {
    if (validPairs.length > 0 && !currentPair) {
      nextQuestion();
    }
  }, [validPairs, currentPair, nextQuestion]);

  if (validPairs.length === 0) {
    return (
      <Card>
        <CardContent className="py-20 text-center">
          <p className="text-muted-foreground">
            Нет валидных пар. Добавьте пары в режиме редактора
          </p>
        </CardContent>
      </Card>
    );
  }

  if (!currentPair) return null;

  return (
    <div className="flex flex-col items-center justify-center min-h-[70vh] gap-8">
      <div className="flex items-center gap-2 text-lg">
        <Sparkles className="w-5 h-5 text-yellow-500" />
        <span className="font-medium">Винстрик:</span>
        <span className="text-2xl font-bold text-green-600">{winStreak}</span>
      </div>

      <Card className="w-full max-w-md">
        <CardContent className="pt-6">
          <RadioGroup
            value={answerMode}
            onValueChange={(v) => setAnswerMode(v as AnswerMode)}
            className="flex justify-center gap-4"
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="multiple-choice" id="mc" />
              <Label htmlFor="mc">3 варианта</Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="all-values" id="all" />
              <Label htmlFor="all">Все значения</Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="manual" id="manual" />
              <Label htmlFor="manual">Ручной ввод</Label>
            </div>
          </RadioGroup>
        </CardContent>
      </Card>

      <Card className="w-full max-w-2xl">
        <CardContent className="p-8">
          <div className="text-center">
            <h2 className="text-6xl md:text-8xl font-bold mb-8">
              {currentPair.key}
            </h2>

            {answerMode === "manual" ? (
              <div className="flex gap-2">
                <Input
                  value={manualInput}
                  onChange={(e) => setManualInput(e.target.value)}
                  onKeyPress={(e) => e.key === "Enter" && handleManualSubmit()}
                  placeholder="Введите ответ..."
                  className="text-lg"
                  disabled={!!feedback}
                />
                <Button onClick={handleManualSubmit} disabled={!!feedback}>
                  Ответить
                </Button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                {options.map((option, idx) => (
                  <Button
                    key={idx}
                    onClick={() => {
                      setSelectedAnswer(option);
                      handleAnswer(option);
                    }}
                    disabled={!!feedback}
                    variant={
                      feedback === "success" && option === currentPair.value
                        ? "default"
                        : feedback === "error" && option === currentPair.value
                        ? "default"
                        : feedback === "error" && option === selectedAnswer
                        ? "destructive"
                        : "outline"
                    }
                    className="h-auto py-4 text-lg"
                  >
                    {option}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {feedback === "success" && (
        <div className="fixed inset-0 pointer-events-none flex items-center justify-center">
          <Check className="w-32 h-32 text-green-500 animate-ping opacity-50" />
        </div>
      )}
      {feedback === "error" && (
        <div className="fixed inset-0 pointer-events-none flex items-center justify-center">
          <X className="w-32 h-32 text-red-500 animate-pulse opacity-50" />
        </div>
      )}
    </div>
  );
}
